import React, { useEffect, useState } from 'react';

const CLIENT_ID = 'your_client_id';
const REDIRECT_URI = 'your_redirect_uri';
const AUTHORIZATION_ENDPOINT = 'https://authorization.server.com/auth';
const TOKEN_ENDPOINT = 'https://authorization.server.com/token';
const SCOPE = 'your_scope';
const CODE_CHALLENGE_METHOD = 'S256';

const generateCodeVerifier = () => {
    const array = new Uint32Array(28);
    window.crypto.getRandomValues(array);
    return Array.from(array, dec => ('0' + dec.toString(16)).slice(-2)).join('');
};

const generateCodeChallenge = async (codeVerifier) => {
    const buffer = new TextEncoder().encode(codeVerifier);
    const hash = await window.crypto.subtle.digest('SHA-256', buffer);
    return btoa(String.fromCharCode(...new Uint8Array(hash)))
        .replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
};

const App = () => {
    const [codeVerifier, setCodeVerifier] = useState('');
    const [codeChallenge, setCodeChallenge] = useState('');

    useEffect(() => {
        const initAuth = async () => {
            const verifier = generateCodeVerifier();
            setCodeVerifier(verifier);
            const challenge = await generateCodeChallenge(verifier);
            setCodeChallenge(challenge);
        };
        initAuth();
    }, []);

    const handleLogin = () => {
        const authUrl = `${AUTHORIZATION_ENDPOINT}?response_type=code&client_id=${CLIENT_ID}&redirect_uri=${REDIRECT_URI}&scope=${SCOPE}&code_challenge=${codeChallenge}&code_challenge_method=${CODE_CHALLENGE_METHOD}`;
        window.location.href = authUrl;
    };

    const handleRedirect = async () => {
        const params = new URLSearchParams(window.location.search);
        const code = params.get('code');

        if (code) {
            const response = await fetch(TOKEN_ENDPOINT, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/x-www-form-urlencoded',
                },
                body: new URLSearchParams({
                    grant_type: 'authorization_code',
                    code: code,
                    redirect_uri: REDIRECT_URI,
                    client_id: CLIENT_ID,
                    code_verifier: codeVerifier,
                }),
            });

            if (response.ok) {
                const data = await response.json();
                localStorage.setItem('access_token', data.access_token);
                localStorage.setItem('refresh_token', data.refresh_token);
            } else {
                console.error('Token exchange failed');
            }
        }
    };

    useEffect(() => {
        handleRedirect();
    }, []);

    return (
        <div>
            <h1>OAuth 2.0 Authentication</h1>
            <button onClick={handleLogin}>Login with OAuth</button>
        </div>
    );
};

export default App;